import{_ as r,C as a,o as i,c as n,j as e,a as o,E as c,ag as l}from"./chunks/framework.HG0H2VLS.js";const v=JSON.parse('{"title":"Breadcrumb","description":"","frontmatter":{},"headers":[],"relativePath":"components/breadcrumb.md","filePath":"components/breadcrumb.md"}'),s={name:"components/breadcrumb.md"};function u(h,t,m,b,p,g){const d=a("ComponentDemo");return i(),n("div",null,[t[0]||(t[0]=e("hr",null,null,-1)),t[1]||(t[1]=e("h2",{id:"title-breadcrumb",tabindex:"-1"},[o("title: Breadcrumb "),e("a",{class:"header-anchor",href:"#title-breadcrumb","aria-label":'Permalink to "title: Breadcrumb"'},"​")],-1)),t[2]||(t[2]=e("h1",{id:"breadcrumb",tabindex:"-1"},[o("Breadcrumb "),e("a",{class:"header-anchor",href:"#breadcrumb","aria-label":'Permalink to "Breadcrumb"'},"​")],-1)),c(d,{src:"/demos/src/components/Breadcrumb/Breadcrumb.html"}),t[3]||(t[3]=l('<h2 id="variant-matrix-verified-from-figma-get-metadata-2026-05-05" tabindex="-1">Variant matrix (verified from Figma <code>get_metadata</code> 2026-05-05) <a class="header-anchor" href="#variant-matrix-verified-from-figma-get-metadata-2026-05-05" aria-label="Permalink to &quot;Variant matrix (verified from Figma `get_metadata` 2026-05-05)&quot;">​</a></h2><p>Single Type axis, 4 variants:</p><table tabindex="0"><thead><tr><th>Type</th><th>Node ID</th><th>Description</th></tr></thead><tbody><tr><td>Default</td><td>2580:11308</td><td>Text-only crumbs (e.g. &quot;Affino &gt; Solutions &gt; For Event Organisers&quot;)</td></tr><tr><td>Home Icon</td><td>2580:11306</td><td>First crumb is a home icon, then text crumbs</td></tr><tr><td>Solid Background</td><td>2580:11307</td><td>Same as Home Icon, wrapped in a soft-bg / bordered pill container</td></tr><tr><td>Dropdown</td><td>2580:11305</td><td>Home icon + dropdown-trigger items (text + chevron-down) + final current page</td></tr></tbody></table><p>No State, Size, or Device axis.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td><code>Type=Default</code></td><td>(no modifier — base <code>.breadcrumb</code>)</td></tr><tr><td><code>Type=Home Icon</code></td><td>(no modifier — first child is <code>.breadcrumb__link--home</code>)</td></tr><tr><td><code>Type=Solid Background</code></td><td><code>.breadcrumb--solid</code></td></tr><tr><td><code>Type=Dropdown</code></td><td>(no modifier — middle items use <code>.breadcrumb__dropdown</code> instead of <code>.breadcrumb__link</code>)</td></tr><tr><td><code>List Item</code> (text crumb)</td><td><code>.breadcrumb__item</code> containing <code>.breadcrumb__link</code></td></tr><tr><td><code>List Item</code> (current page, semibold)</td><td><code>.breadcrumb__item.breadcrumb__item--current</code> (with <code>aria-current=&quot;page&quot;</code>)</td></tr><tr><td><code>List Item</code> (chevron-right separator)</td><td><code>.breadcrumb__separator</code> (with <code>aria-hidden=&quot;true&quot;</code>)</td></tr><tr><td><code>Link - Home</code></td><td><code>.breadcrumb__link.breadcrumb__link--home</code></td></tr><tr><td><code>Button</code> (dropdown trigger)</td><td><code>.breadcrumb__dropdown</code> (<code>&lt;button type=&quot;button&quot; aria-haspopup=&quot;menu&quot;&gt;</code>)</td></tr></tbody></table><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><h3 id="typography-all-link-current-items" tabindex="-1">Typography (all link / current items) <a class="header-anchor" href="#typography-all-link-current-items" aria-label="Permalink to &quot;Typography (all link / current items)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>font-family</td><td><code>var(--ai-font-title)</code></td></tr><tr><td>font-size</td><td><code>var(--ai-font-fixed-xs)</code> (14px)</td></tr><tr><td>line-height</td><td><code>var(--ai-leading-md)</code> (24px)</td></tr><tr><td>font-weight (link)</td><td><code>var(--ai-font-medium)</code></td></tr><tr><td>font-weight (current)</td><td><code>var(--ai-font-semibold)</code></td></tr><tr><td>color (link)</td><td><code>var(--ai-text-secondary)</code></td></tr><tr><td>color (link hover)</td><td><code>var(--ai-text-primary)</code></td></tr><tr><td>color (current)</td><td><code>var(--ai-text-primary)</code></td></tr></tbody></table><h3 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>List gap</td><td><code>var(--ai-spacing-2)</code> (6px)</td></tr><tr><td>Item height</td><td><code>var(--ai-leading-md)</code> (24px — matches text line-height)</td></tr></tbody></table><h3 id="icons" tabindex="-1">Icons <a class="header-anchor" href="#icons" aria-label="Permalink to &quot;Icons&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Icon</th><th>Lucide name</th><th>Size token</th><th>Colour token</th></tr></thead><tbody><tr><td>Separator</td><td><code>chevron-right</code></td><td><code>--ai-icon-size-sm</code> (16px)</td><td><code>--ai-icon-contrast</code></td></tr><tr><td>Home</td><td><code>house</code></td><td><code>--ai-icon-size-sm</code> (16px)</td><td><code>--ai-icon-secondary</code></td></tr><tr><td>Dropdown trigger</td><td><code>chevron-down</code></td><td><code>--ai-icon-size-sm</code> (16px)</td><td><code>currentColor</code> (inherits the button&#39;s text-secondary; see Token gap notes)</td></tr></tbody></table><h3 id="type-solid-background-container" tabindex="-1">Type=Solid Background container <a class="header-anchor" href="#type-solid-background-container" aria-label="Permalink to &quot;Type=Solid Background container&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>background-color</td><td><code>var(--ai-surface-minimal)</code></td></tr><tr><td>border</td><td><code>1px solid var(--ai-border-secondary)</code></td></tr><tr><td>border-radius</td><td><code>var(--ai-radius-md)</code> (8px)</td></tr><tr><td>padding</td><td><code>var(--ai-spacing-3) var(--ai-spacing-5)</code> (8px 16px)</td></tr></tbody></table><p>The padding/bg/border live on the inner <code>.breadcrumb__list</code> (the <code>&lt;ol&gt;</code>) so the <code>&lt;nav&gt;</code> itself stays a transparent inline-block. This keeps the chrome scoped to the visible list without affecting external siblings.</p><hr><h2 id="token-gap-notes" tabindex="-1">Token gap notes <a class="header-anchor" href="#token-gap-notes" aria-label="Permalink to &quot;Token gap notes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Figma binding</th><th>Resolution</th></tr></thead><tbody><tr><td>Dropdown chevron-down colour</td><td>No explicit Figma variable bound to the chevron-down icon (variable defs on the icon node return empty).</td><td>Used <code>currentColor</code> so it inherits from the dropdown button&#39;s <code>--ai-text-secondary</code>. Visually matches the text and adjusts on hover with the button. Worth raising with the designer.</td></tr><tr><td>Frame name</td><td>Figma frame is named &quot;Numbered List&quot; — clearly the wrong name for what is structurally a breadcrumb pattern.</td><td>Component code-named <code>Breadcrumb</code> per established convention. Worth raising with the designer to rename the Figma frame.</td></tr></tbody></table><p>No primitive Tailwind colours used. No hardcoded px / hex values (border widths stay 1px per the project rule).</p><hr><h2 id="sub-elements" tabindex="-1">Sub-elements <a class="header-anchor" href="#sub-elements" aria-label="Permalink to &quot;Sub-elements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Class</th><th>Notes</th></tr></thead><tbody><tr><td>Wrapper</td><td><code>&lt;nav class=&quot;breadcrumb&quot;&gt;</code></td><td><code>aria-label=&quot;Breadcrumb&quot;</code>. Optional <code>--solid</code> modifier.</td></tr><tr><td>List</td><td><code>&lt;ol class=&quot;breadcrumb__list&quot;&gt;</code></td><td>Holds the <code>&lt;li&gt;</code> items. Solid bg lives on this element.</td></tr><tr><td>Item (link)</td><td><code>&lt;li class=&quot;breadcrumb__item&quot;&gt;&lt;a class=&quot;breadcrumb__link&quot;&gt;…&lt;/a&gt;&lt;/li&gt;</code></td><td>Default state.</td></tr><tr><td>Item (home)</td><td><code>&lt;li class=&quot;breadcrumb__item&quot;&gt;&lt;a class=&quot;breadcrumb__link breadcrumb__link--home&quot; aria-label=&quot;Home&quot;&gt;&lt;i data-lucide=&quot;house&quot;&gt;&lt;/i&gt;&lt;/a&gt;&lt;/li&gt;</code></td><td>First crumb in Home Icon / Solid Background / Dropdown variants.</td></tr><tr><td>Separator</td><td><code>&lt;li class=&quot;breadcrumb__separator&quot; aria-hidden=&quot;true&quot;&gt;&lt;i data-lucide=&quot;chevron-right&quot;&gt;&lt;/i&gt;&lt;/li&gt;</code></td><td>Between every item. Hidden from screen readers.</td></tr><tr><td>Current page</td><td><code>&lt;li class=&quot;breadcrumb__item breadcrumb__item--current&quot; aria-current=&quot;page&quot;&gt;…&lt;/li&gt;</code></td><td>No <code>&lt;a&gt;</code> — non-interactive. Last item only.</td></tr><tr><td>Dropdown trigger</td><td><code>&lt;div class=&quot;dropdown&quot;&gt;&lt;button class=&quot;breadcrumb__dropdown dropdown__trigger&quot; aria-haspopup=&quot;menu&quot; aria-expanded=&quot;false&quot;&gt;…&lt;i data-lucide=&quot;chevron-down&quot;&gt;&lt;/i&gt;&lt;/button&gt;&lt;div class=&quot;dropdown__panel&quot; role=&quot;menu&quot;&gt;…&lt;/div&gt;&lt;/div&gt;</code></td><td>Used in Type=Dropdown for items 2..n-1. Composes the Dropdown component for behaviour; the breadcrumb only contributes the trigger visual style.</td></tr></tbody></table><hr><h2 id="interaction-model" tabindex="-1">Interaction model <a class="header-anchor" href="#interaction-model" aria-label="Permalink to &quot;Interaction model&quot;">​</a></h2><ul><li><strong>Links and home icon:</strong> standard <code>&lt;a&gt;</code> navigation. Hover changes colour from <code>text-secondary</code> → <code>text-primary</code> via <code>--ai-transition-default</code>.</li><li><strong>Current page:</strong> non-interactive — rendered as plain text inside the <code>&lt;li&gt;</code> with <code>aria-current=&quot;page&quot;</code>. No href, no hover.</li><li><strong>Dropdown triggers:</strong> rendered as <code>&lt;button type=&quot;button&quot; class=&quot;breadcrumb__dropdown dropdown__trigger&quot; aria-haspopup=&quot;menu&quot; aria-expanded=&quot;false&quot;&gt;</code> wrapped in <code>&lt;div class=&quot;dropdown&quot;&gt;</code> with a sibling <code>&lt;div class=&quot;dropdown__panel&quot; role=&quot;menu&quot;&gt;</code>. The Breadcrumb supplies the visual style via <code>.breadcrumb__dropdown</code>; the Dropdown component supplies the open/close behaviour, panel positioning, click-outside, Escape handling, and chevron rotation via the <code>.dropdown__trigger</code> hook. Breadcrumb ships no JS of its own — <code>Dropdown.js</code> (auto-init on <code>DOMContentLoaded</code>) manages all interaction. Hover styling (<code>text-secondary → text-primary</code>) lives on <code>.breadcrumb__dropdown</code>; rotation (<code>chevron-down</code> 180°) is provided by Dropdown&#39;s <code>[aria-expanded=&quot;true&quot;]</code> rule.</li></ul><hr><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>Wrapper is <code>&lt;nav aria-label=&quot;Breadcrumb&quot;&gt;</code> so screen-reader users get a clear landmark.</li><li>Separators are decorative — <code>&lt;li aria-hidden=&quot;true&quot;&gt;</code> and the icons inside have no accessible name (no <code>aria-label</code> on the <code>&lt;i&gt;</code>). They are not announced.</li><li>Current page uses <code>aria-current=&quot;page&quot;</code> instead of being a link, signalling &quot;this is where you are.&quot;</li><li>Home icon link has <code>aria-label=&quot;Home&quot;</code> since it has no visible text.</li><li>Dropdown triggers have <code>aria-haspopup=&quot;menu&quot;</code>. When wired to a real dropdown component the consumer should also manage <code>aria-expanded</code> and <code>aria-controls</code> on the button.</li></ul><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-05: First Figma-verified spec. <code>get_metadata</code> on component set <code>2580:11309</code> enumerated all 4 Type variants; <code>get_design_context</code> on each variant resolved tokens; targeted <code>get_variable_defs</code> on the separator (<code>2580:11172</code>) and home icon (<code>2580:11192</code>) nodes pinpointed <code>--ai-icon-contrast</code> vs <code>--ai-icon-secondary</code> respectively. The dropdown chevron icon node had no token binding — fell back to <code>currentColor</code> (documented in Token gap notes).</li></ul>',34))])}const _=r(s,[["render",u]]);export{v as __pageData,_ as default};
